define ptr @pos_not_i8(ptr %foo, i64 %x) {
  %idx = srem i64 %x, 4
  %p = getelementptr inbounds nuw i32, ptr %foo, i64 %idx
  ret ptr %p
}

define ptr @neg_missing_nuw(ptr %foo, i64 %x) {
  %idx = srem i64 %x, 4
  %p = getelementptr inbounds i8, ptr %foo, i64 %idx
